mapper.sql:
WHERE rp.deleted = 0

    AND (sp.student_no LIKE CONCAT('%', #{query.studentKeyword}, '%')
      OR sp.chinese_name LIKE CONCAT('%', #{query.studentKeyword}, '%')
      OR sp.english_name LIKE CONCAT('%', #{query.studentKeyword}, '%'))


    AND rp.permit_type = #{query.permitType}


    AND rp.status = #{query.status}


    AND rp.valid_until >= #{query.expireStart}


    AND rp.valid_until <= #{query.expireEnd}
